def _separate_paren_groups_helper(paren_string: str, start_pos: int, current_string: List[str]):
    """Helper to separate_paren_groups that does the actual work."""
    if start_pos >= len(paren_string):
        return ['.'.join(current_string)]

    current_char = paren_string[start_pos]
    if current_char == '(':
        # Add this group to the current string
        current_string.append('(')
        # Recurse to see if there are any nested groups
        current_string_copy = current_string.copy()
        nested = _separate_paren_groups_helper(paren_string, start_pos + 1, current_string_copy)
        current_string.pop()
        if nested:
            return nested

    elif current_char == ')':
        # We reached the end of the string, so add the current string to the list
        current_string.append(')')
        return ['.'.join(current_string)]

    elif current_char == ' ':
        # Ignore spaces
        return _separate_paren_groups_helper(paren_string, start_pos + 1, current_string)

    # We have a non-space, non-parenthesis character, so this must be part of the current group.
    # Move forward in the string and recurse
    return _separate_paren_groups_helper(paren_string, start_pos + 1, current_string)

